<?php

if (!function_exists('wh_t')) {
  function wh_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('wh_h')) {
  function wh_h($value) { return htmlspecialchars((string)$value, ENT_QUOTES, 'UTF-8'); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
require_once "../../inc/accounting_journal.php";
session_check_json();
$act=isset($_GET['act'])?$_GET['act']:'';
function msa_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');echo json_encode(array_merge(array('status'=>$s,'error_message'=>$m),$x));exit;}
function msa_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function msa_in($k,$d=''){return isset($_POST[$k])?trim((string)$_POST[$k]):(isset($_GET[$k])?trim((string)$_GET[$k]):$d);}
function msa_qty($v){return round((float)str_replace(',','.',trim((string)$v)),5);}
function msa_valid_date($d){$x=DateTime::createFromFormat('Y-m-d',$d);return $x&&$x->format('Y-m-d')===$d;}
function msa_next_no($date){global $db;$prefix='MSA'.date('Ym',strtotime($date));$r=$db->fetch("SELECT adjustment_no FROM erp_manual_stock_adjustment WHERE adjustment_no LIKE ? ORDER BY adjustment_no DESC LIMIT 1",array($prefix.'%'));$n=1;if($r&&preg_match('/(\d{5})$/',$r->adjustment_no,$m))$n=(int)$m[1]+1;return $prefix.sprintf('%05d',$n);}
function msa_stock_qty($material,$plant,$sloc,$bin,$stockType){global $db;$r=$db->fetch("SELECT COALESCE(SUM(qty_sisa),0) qty FROM stock_layer WHERE kode=? AND qty_sisa>0 AND IFNULL(plant_id,0)=IFNULL(?,0) AND IFNULL(storage_location_id,0)=IFNULL(?,0) AND IFNULL(storage_bin_id,0)=IFNULL(?,0) AND stock_type=?",array($material,$plant,$sloc,$bin,$stockType));return $r?(float)$r->qty:0;}
function msa_material($code){global $db;return $db->fetch("SELECT kd_barang,nm_barang,satuan FROM barang WHERE kd_barang=? LIMIT 1",array($code));}
if($act==='material_search'){
  $term=msa_in('term');$type=msa_in('adjustment_type','INCREASE');$plant=(int)msa_in('plant_id');$sloc=(int)msa_in('storage_location_id');$bin=(int)msa_in('storage_bin_id');$stockType=msa_in('stock_type','UNRESTRICTED');$kw='%'.$term.'%';
  if($type==='DECREASE'){
    $where=" WHERE sl.qty_sisa>0 ";$p=array();
    if($plant>0){$where.=" AND sl.plant_id=? ";$p[]=$plant;}if($sloc>0){$where.=" AND sl.storage_location_id=? ";$p[]=$sloc;}if($bin>0){$where.=" AND sl.storage_bin_id=? ";$p[]=$bin;}if($stockType!==''){$where.=" AND sl.stock_type=? ";$p[]=$stockType;}
    $p[]=$term;$p[]=$kw;$p[]=$kw;
    $rows=$db->query("SELECT sl.kode,b.nm_barang,b.satuan,COALESCE(SUM(sl.qty_sisa),0) stock FROM stock_layer sl LEFT JOIN barang b ON b.kd_barang=sl.kode $where AND (?='' OR sl.kode LIKE ? OR b.nm_barang LIKE ?) GROUP BY sl.kode,b.nm_barang,b.satuan HAVING stock>0 ORDER BY sl.kode LIMIT 30",$p);
  }else{
    $rows=$db->query("SELECT b.kd_barang kode,b.nm_barang,b.satuan,COALESCE(SUM(sl.qty_sisa),0) stock FROM barang b LEFT JOIN stock_layer sl ON sl.kode=b.kd_barang AND sl.qty_sisa>0 WHERE COALESCE(b.status,1)=1 AND (?='' OR b.kd_barang LIKE ? OR b.nm_barang LIKE ?) GROUP BY b.kd_barang,b.nm_barang,b.satuan ORDER BY b.kd_barang LIMIT 30",array($term,$kw,$kw));
  }
  $res=array();foreach($rows as $r)$res[]=array('id'=>$r->kode,'text'=>$r->kode.' - '.$r->nm_barang.' | Stock '.number_format((float)$r->stock,5,',','.').' '.$r->satuan,'material_name'=>$r->nm_barang,'uom'=>$r->satuan,'stock'=>(float)$r->stock);echo json_encode(array('results'=>$res));exit;
}
if($act==='stock_qty'){ $m=msa_in('material_code');echo json_encode(array('stock'=>msa_stock_qty($m,(int)msa_in('plant_id'),(int)msa_in('storage_location_id'),(int)msa_in('storage_bin_id'),msa_in('stock_type','UNRESTRICTED'))));exit; }
if($act==='post'){
  $type=msa_in('adjustment_type');$docDate=msa_in('document_date');$postDate=msa_in('posting_date');$plant=(int)msa_in('plant_id');$sloc=(int)msa_in('storage_location_id');$bin=(int)msa_in('storage_bin_id');$stockType=msa_in('stock_type','UNRESTRICTED');$reason=msa_in('reason_code');$reasonText=msa_in('reason_text');
  if(!in_array($type,array('INCREASE','DECREASE'),true))msa_json('error','Adjustment type tidak valid.');if(!msa_valid_date($docDate)||!msa_valid_date($postDate))msa_json('error','Tanggal dokumen/posting wajib valid.');if($plant<=0||$sloc<=0)msa_json('error','Plant dan Storage Location wajib dipilih.');if(!in_array($stockType,array('UNRESTRICTED','QUALITY','BLOCKED'),true))msa_json('error','Stock type tidak valid.');if($reason==='')msa_json('error','Reason code wajib diisi.');
  $materials=isset($_POST['material_code'])&&is_array($_POST['material_code'])?$_POST['material_code']:array();if(count($materials)<1)msa_json('error','Minimal 1 item material wajib diisi.');
  $username=isset($_SESSION['username'])?$_SESSION['username']:'system';$adjNo=msa_next_no($postDate);$move=$type==='INCREASE'?'701':'702';$totalQty=0;$totalAmount=0;
  $db->query('START TRANSACTION');
  $ok=$db->insert('erp_manual_stock_adjustment',array('adjustment_no'=>$adjNo,'document_date'=>$docDate,'posting_date'=>$postDate,'adjustment_type'=>$type,'movement_type'=>$move,'plant_id'=>$plant,'storage_location_id'=>$sloc,'storage_bin_id'=>$bin?:null,'stock_type'=>$stockType,'reason_code'=>$reason,'reason_text'=>$reasonText,'status'=>'POSTED','created_by'=>$username));
  if(!$ok){$e=$db->getErrorMessage();$db->query('ROLLBACK');msa_json('error',$e?:'Header adjustment gagal disimpan.');}
  $hid=$db->last_insert_id();$line=1;$accountingItems=array();
  foreach($materials as $i=>$mat){$mat=trim((string)$mat);if($mat==='')continue;$qty=msa_qty(isset($_POST['qty'][$i])?$_POST['qty'][$i]:0);$price=msa_qty(isset($_POST['price'][$i])?$_POST['price'][$i]:0);$remarks=isset($_POST['line_remarks'][$i])?trim((string)$_POST['line_remarks'][$i]):'';if($qty<=0){$db->query('ROLLBACK');msa_json('error','Qty item '.$mat.' wajib lebih dari 0.');}$b=msa_material($mat);if(!$b){$db->query('ROLLBACK');msa_json('error','Material '.$mat.' tidak ditemukan.');}$sys=msa_stock_qty($mat,$plant,$sloc,$bin,$stockType);if($type==='DECREASE'&&$sys+0.00001<$qty){$db->query('ROLLBACK');msa_json('error','Stock '.$mat.' tidak cukup. Stock '.$sys.', adjustment '.$qty);}
    if($price<=0){$db->query('ROLLBACK');msa_json('error','Price item '.$mat.' wajib lebih dari 0 untuk posting jurnal.');}
    $amount=round($qty*$price,2);$detailId=0;$materialDocId=null;$sourceIds=array();$newLayerId=null;$noBpb=$adjNo;$noAju='';$noDokpab='';$jenis='NON';
    $ok=$db->insert('erp_manual_stock_adjustment_detail',array('adjustment_id'=>$hid,'line_no'=>$line,'material_code'=>$mat,'material_name'=>$b->nm_barang,'qty'=>$qty,'uom'=>$b->satuan,'price'=>$price,'amount'=>$amount,'system_qty_before'=>$sys,'plant_id'=>$plant,'storage_location_id'=>$sloc,'storage_bin_id'=>$bin?:null,'stock_type'=>$stockType,'remarks'=>$remarks));
    if(!$ok){$e=$db->getErrorMessage();$db->query('ROLLBACK');msa_json('error',$e?:'Detail adjustment gagal disimpan.');}$detailId=$db->last_insert_id();
    if($type==='DECREASE'){
      $remain=$qty;$layers=$db->query("SELECT * FROM stock_layer WHERE kode=? AND qty_sisa>0 AND IFNULL(plant_id,0)=IFNULL(?,0) AND IFNULL(storage_location_id,0)=IFNULL(?,0) AND IFNULL(storage_bin_id,0)=IFNULL(?,0) AND stock_type=? ORDER BY COALESCE(tgl_masuk,DATE(created_at)),id FOR UPDATE",array($mat,$plant,$sloc,$bin,$stockType));
      foreach($layers as $l){if($remain<=0)break;$take=min($remain,(float)$l->qty_sisa);if($take<=0)continue;$db->query("UPDATE stock_layer SET qty_sisa=qty_sisa-? WHERE id=? AND qty_sisa>=?",array($take,$l->id,$take));$remain-=$take;$sourceIds[]=$l->id;$noBpb=$l->no_bpb;$noAju=$l->no_aju;$noDokpab=$l->no_dokpab;$jenis=$l->jenis_dokpab;}
      if($remain>0.00001){$db->query('ROLLBACK');msa_json('error','Stock layer FIFO '.$mat.' tidak cukup.');}
    }
    $dt=array('no_ref'=>$adjNo,'ref_pengganti'=>$adjNo,'no_aju'=>$noAju,'no_dokpab'=>$noDokpab,'move_code'=>$move,'posisi'=>'GUDANG','no_urut'=>$line,'qty'=>$type==='INCREASE'?$qty:-$qty,'price'=>$price,'amount'=>$amount,'kd_barang'=>$mat,'lokasi'=>'GUDANG','document_date'=>$docDate,'posting_date'=>$postDate,'user'=>$username,'direction'=>$type==='INCREASE'?'IN':'OUT','ref_type'=>'MANUAL_ADJUST','ref_id'=>$hid,'ref_detail_id'=>$detailId,'uom'=>$b->satuan,'reason'=>$reason.' '.$reasonText,'created_by'=>$username,'no_bpb'=>$noBpb,'plant_id'=>$plant,'storage_location_id'=>$sloc,'storage_bin_id'=>$bin?:null,'stock_type'=>$stockType,'destination_storage_location_id'=>$sloc,'destination_storage_bin_id'=>$bin?:null,'destination_stock_type'=>$stockType,'destination_material_code'=>$mat,'remark'=>'Manual Stock Adjustment '.$type.' '.$adjNo);
    if(!$db->insert('detail_transaksi',$dt)){$e=$db->getErrorMessage();$db->query('ROLLBACK');msa_json('error',$e?:'Material document gagal dibuat.');}$materialDocId=$db->last_insert_id();
    if($type==='INCREASE'){if(!$db->insert('stock_layer',array('kode'=>$mat,'qty_masuk'=>$qty,'qty_sisa'=>$qty,'no_aju'=>'','no_dokpab'=>'','lokasi'=>'GUDANG','stock_type'=>$stockType,'plant_id'=>$plant,'storage_location_id'=>$sloc,'storage_bin_id'=>$bin?:null,'jenis_dokpab'=>'NON','ref_table'=>'detail_transaksi','ref_id'=>$materialDocId,'tgl_masuk'=>$postDate,'no_bpb'=>$adjNo))){$e=$db->getErrorMessage();$db->query('ROLLBACK');msa_json('error',$e?:'Stock layer adjustment masuk gagal dibuat.');}$newLayerId=$db->last_insert_id();}
    $db->update('erp_manual_stock_adjustment_detail',array('material_doc_id'=>$materialDocId,'source_layer_ids'=>implode(',',$sourceIds),'new_stock_layer_id'=>$newLayerId),'id',$detailId);
    $accountingItems[]=array('kode'=>$mat,'amount'=>$amount,'valuta'=>'IDR','kurs'=>1);
    $totalQty+=$qty;$totalAmount+=$amount;$line++;
  }
  if($line===1){$db->query('ROLLBACK');msa_json('error','Tidak ada item valid untuk diposting.');}
  $db->update('erp_manual_stock_adjustment',array('total_qty'=>$totalQty,'total_amount'=>$totalAmount,'updated_at'=>date('Y-m-d H:i:s')),'id',$hid);
  $journalResult=accounting_post_auto_journal($type==='INCREASE'?'manual_adjust_increase':'manual_adjust_decrease','',$accountingItems,array('no_bukti'=>$adjNo,'tgl_jurnal'=>$postDate,'ket'=>'Manual Stock Adjustment '.$type.' '.$adjNo,'valuta'=>'IDR','kurs'=>1,'source_module'=>'MANUAL_STOCK_ADJUSTMENT'));
  if($journalResult!==true){$db->query('ROLLBACK');msa_json('error',$journalResult);}
  if(function_exists('simpan_log'))simpan_log('User '.$username.' posting Manual Stock Adjustment '.$adjNo.' '.$type.' pada '.date('Y-m-d H:i:s'),$username);
  $db->query('COMMIT');msa_json('good','',array('adjustment_no'=>$adjNo));
}
if($act==='detail'){
  $id=(int)msa_in('id');$h=$db->fetch("SELECT h.*,ep.plant_code,es.storage_code,eb.bin_code FROM erp_manual_stock_adjustment h LEFT JOIN erp_plant ep ON ep.id=h.plant_id LEFT JOIN erp_storage_location es ON es.id=h.storage_location_id LEFT JOIN erp_storage_bin eb ON eb.id=h.storage_bin_id WHERE h.id=? LIMIT 1",array($id));if(!$h){echo '<div class="alert alert-warning">Adjustment tidak ditemukan.</div>';exit;}$items=$db->query("SELECT * FROM erp_manual_stock_adjustment_detail WHERE adjustment_id=? ORDER BY line_no,id",array($id));
	  echo '<h3 style="margin-top:0">'.msa_h($h->adjustment_no).' <small>MvT '.msa_h($h->movement_type).' / '.msa_h($h->adjustment_type).'</small></h3><div class="row"><div class="col-sm-3"><strong>'.wh_h(wh_t('warehouse_posting_date', 'Posting Date')).'</strong><br>'.msa_h($h->posting_date).'</div><div class="col-sm-3"><strong>'.wh_h(wh_t('warehouse_location', 'Location')).'</strong><br>'.msa_h(trim($h->plant_code.' / '.$h->storage_code.' / '.$h->bin_code,' /')).'</div><div class="col-sm-3"><strong>'.wh_h(wh_t('warehouse_stock_type', 'Stock Type')).'</strong><br>'.msa_h($h->stock_type).'</div><div class="col-sm-3"><strong>'.wh_h(wh_t('warehouse_reason', 'Reason')).'</strong><br>'.msa_h($h->reason_code.' - '.$h->reason_text).'</div></div><hr><div class="table-responsive"><table class="table table-bordered table-condensed"><thead><tr class="bg-gray"><th>'.wh_h(wh_t('warehouse_line', 'Line')).'</th><th>'.wh_h(wh_t('warehouse_material', 'Material')).'</th><th class="text-right">'.wh_h(wh_t('warehouse_system_before', 'System Before')).'</th><th class="text-right">'.wh_h(wh_t('warehouse_qty', 'Qty')).'</th><th>'.wh_h(wh_t('warehouse_uom', 'UOM')).'</th><th class="text-right">'.wh_h(wh_t('warehouse_price', 'Price')).'</th><th class="text-right">'.wh_h(wh_t('warehouse_amount', 'Amount')).'</th><th>'.wh_h(wh_t('warehouse_material_doc', 'Material Doc')).'</th><th>'.wh_h(wh_t('warehouse_layer_ref', 'Layer Ref')).'</th><th>'.wh_h(wh_t('warehouse_remarks', 'Remarks')).'</th></tr></thead><tbody>';
  foreach($items as $it)echo '<tr><td>'.(int)$it->line_no.'</td><td><strong>'.msa_h($it->material_code).'</strong><br><small>'.msa_h($it->material_name).'</small></td><td class="text-right">'.number_format((float)$it->system_qty_before,5,',','.').'</td><td class="text-right">'.number_format((float)$it->qty,5,',','.').'</td><td>'.msa_h($it->uom).'</td><td class="text-right">'.number_format((float)$it->price,5,',','.').'</td><td class="text-right">'.number_format((float)$it->amount,2,',','.').'</td><td>#'.(int)$it->material_doc_id.'</td><td>'.msa_h($it->source_layer_ids?:($it->new_stock_layer_id?'New #'.$it->new_stock_layer_id:'-')).'</td><td>'.msa_h($it->remarks).'</td></tr>';
  echo '</tbody></table></div>';exit;
}
if($act==='excel'){
  $initial=ob_get_level();ob_start();ini_set('display_errors','0');error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require '../../inc/lib/PHPExcel.php';require_once '../../inc/excel_style_helper.php';PHPExcel_Shared_File::setUseUploadTempDirectory(true);
  $from=msa_in('tgl_awal',date('Y-m-01'));$to=msa_in('tgl_akhir',date('Y-m-d'));$p=array($from,$to);$where=" WHERE h.posting_date BETWEEN ? AND ? ";if(msa_in('adjustment_type')!==''){$where.=" AND h.adjustment_type=? ";$p[]=msa_in('adjustment_type');}
  $rows=$db->query("SELECT h.adjustment_no,h.posting_date,h.document_date,h.adjustment_type,h.movement_type,h.reason_code,h.reason_text,ep.plant_code,es.storage_code,eb.bin_code,h.stock_type,d.line_no,d.material_code,d.material_name,d.system_qty_before,d.qty,d.uom,d.price,d.amount,d.material_doc_id,d.remarks,h.created_by,h.created_at FROM erp_manual_stock_adjustment h JOIN erp_manual_stock_adjustment_detail d ON d.adjustment_id=h.id LEFT JOIN erp_plant ep ON ep.id=h.plant_id LEFT JOIN erp_storage_location es ON es.id=h.storage_location_id LEFT JOIN erp_storage_bin eb ON eb.id=h.storage_bin_id $where ORDER BY h.posting_date DESC,h.id DESC,d.line_no",$p);
  $excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Manual Adjustment'));$heads=array(erp_export_label("No"),erp_export_label("Adjustment No"),erp_export_label("Posting Date"),erp_export_label("Document Date"),erp_export_label("Type"),erp_export_label("MvT"),erp_export_label("Reason"),erp_export_label("Plant"),erp_export_label("SLoc"),erp_export_label("Bin"),erp_export_label("Stock Type"),erp_export_label("Line"),erp_export_label("Material"),erp_export_label("Material Name"),erp_export_label("System Before"),erp_export_label("Qty"),erp_export_label("UOM"),erp_export_label("Price"),erp_export_label("Amount"),erp_export_label("Material Doc"),erp_export_label("Remarks"),erp_export_label("Created By"),erp_export_label("Created At"));foreach($heads as $i=>$v)$sheet->setCellValueByColumnAndRow($i,4,$v);$r=5;$n=1;foreach($rows as $row){$vals=array($n++,$row->adjustment_no,$row->posting_date,$row->document_date,$row->adjustment_type,$row->movement_type,$row->reason_code.' - '.$row->reason_text,$row->plant_code,$row->storage_code,$row->bin_code,$row->stock_type,$row->line_no,$row->material_code,$row->material_name,(float)$row->system_qty_before,(float)$row->qty,$row->uom,(float)$row->price,(float)$row->amount,$row->material_doc_id,$row->remarks,$row->created_by,$row->created_at);foreach($vals as $i=>$v)$sheet->setCellValueByColumnAndRow($i,$r,$v);$r++;}
  erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('MANUAL STOCK ADJUSTMENT - SAP MM'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$r-1),'column_count'=>23,'numeric_columns'=>array('O','P','R','S'),'filters'=>array('Periode'=>erp_export_period_text($from,$to),'Type'=>msa_in('adjustment_type'))));$tmp=erpkb_excel_temp_file('manual_stock_adjustment_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();header('Content-Type:text/plain; charset=utf-8');echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="manual_stock_adjustment_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
}
